/**
 * n8n Function node
 * Output ONLY:
 * messageId, guildId, channelId, authorId, authorName,
 * content,
 * leadType,
 * howDidYouHearAboutUs,
 * referredBy,
 * leadQualifier,
 * imageAttachments[]
 */

// ---------- Helpers ----------
const firstNonEmpty = (...vals) => {
  for (const v of vals) {
    if (v !== undefined && v !== null && v !== "") return v;
  }
  return null;
};

function isImageAttachment(att) {
  const ct = String(
    att?.content_type ?? att?.contentType ?? ""
  ).toLowerCase();

  const name = String(
    att?.filename ?? att?.name ?? ""
  ).toLowerCase();

  if (ct.startsWith("image/")) return true;
  return /\.(png|jpe?g|gif|webp|bmp|tiff?)$/i.test(name);
}

function pickImageFields(att) {
  return {
    id: firstNonEmpty(att?.id),
    name: firstNonEmpty(att?.filename, att?.name),
    url: firstNonEmpty(att?.url, att?.attachment),
    proxyURL: firstNonEmpty(att?.proxy_url, att?.proxyURL, att?.proxyUrl),
    size: firstNonEmpty(att?.size),
    width: firstNonEmpty(att?.width),
    height: firstNonEmpty(att?.height),
    contentType: firstNonEmpty(att?.content_type, att?.contentType),
    title: firstNonEmpty(att?.title),
    description: firstNonEmpty(att?.description),
  };
}

// ---------- Main ----------
const msg = $input.first().json;

// ✅ grab ids from either camelCase or snake_case or nested author object
const channelId = firstNonEmpty(msg?.channelId, msg?.channel_id);
const authorId = firstNonEmpty(msg?.authorId, msg?.author?.id);
const authorName = firstNonEmpty(
  msg?.authorName,
  msg?.author?.username,
  msg?.author?.global_name
);

// ✅ attachments can be either msg.attachments (your note) or discord message.attachments
const attachments = Array.isArray(msg?.attachments) ? msg.attachments : [];

const imageAttachments = attachments
  .filter(isImageAttachment)
  .map(pickImageFields);

const output = {
  messageId: firstNonEmpty(msg?.messageId, msg?.id),
  guildId: firstNonEmpty(msg?.guildId, msg?.guild_id, "753455160209965106"), // fallback safe
  channelId,
  authorId,
  authorName,
  content: firstNonEmpty(msg?.content, ""), // keep empty string if empty
  leadType: "HiPages Lead",
  howDidYouHearAboutUs: "HiPages",
  referredBy: null,
  leadQualifier: "Good",
  imageAttachments,
};

return [{ json: output }];

// n8n Code node (Once for All Items)
// FIXED: Robust parsing for truncated AI JSON + CRM enquiry formatting
// - Recovers fields even when AI response is cut off mid-key (status: incomplete)
// - Enquiry formatted for Google Sheets (CRM clean) and works even if Discord message is missing
// - Removes imageAttachments here (you will merge later)
// - Fixes address: "Carindale, 4152" => "Carindale"
// - Adds Timestamp (Australia/Brisbane)
// - fileName: FirstNameLastName-DD-MM-YYYY-HiLead
//
// CHANGE REQUEST APPLIED:
// - Removed messageId, channelId, authorId, authorName from the output completely
// - Also deletes these keys if they appear in AI JSON (lead.*)
//
// NEW FIX:
// - Prevent Google Sheets formula errors/injection by prefixing ' when a value starts with = + - @
//   (especially enquiry which starts with "=====")

const inputItems = $input.all();
const outputItems = [];

// ---------- Brisbane Timestamp ----------
function nowBrisbaneTimestamp() {
  const tz = 'Australia/Brisbane';
  const d = new Date();

  const parts = new Intl.DateTimeFormat('en-AU', {
    timeZone: tz,
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
  }).formatToParts(d);

  const get = (type) => parts.find(p => p.type === type)?.value;
  return `${get('day')}/${get('month')}/${get('year')}, ${get('hour')}:${get('minute')}:${get('second')}`;
}

// ---------- Filename ----------
function formatDDMMYYYY() {
  const d = new Date();
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = String(d.getFullYear());
  return `${dd}-${mm}-${yyyy}`;
}
function safeName(s) {
  return String(s || '').trim().replace(/\s+/g, '').replace(/[^a-zA-Z0-9_-]/g, '');
}
function buildFileName(firstName, lastName) {
  const name = (safeName(firstName) + safeName(lastName)) || 'Unknown';
  return `${name}-${formatDDMMYYYY()}-HiLead`;
}

// ---------- Google Sheets safety (formula injection / leading equals fix) ----------
function safeForGoogleSheets(value) {
  const s = String(value ?? '');
  // Google Sheets treats strings starting with these as formulas
  return /^[=+\-@]/.test(s) ? "'" + s : s;
}

// ---------- Deep search helper (returns FIRST found value, may be object/array/string) ----------
function deepFindKey(root, keyName, maxDepth = 12) {
  const seen = new Set();
  const queue = [{ value: root, depth: 0 }];

  while (queue.length) {
    const { value, depth } = queue.shift();
    if (value === null || value === undefined) continue;
    if (typeof value !== 'object') continue;
    if (seen.has(value)) continue;
    seen.add(value);

    if (Object.prototype.hasOwnProperty.call(value, keyName)) {
      return value[keyName];
    }

    if (depth >= maxDepth) continue;

    if (Array.isArray(value)) {
      for (const v of value) queue.push({ value: v, depth: depth + 1 });
    } else {
      for (const k of Object.keys(value)) queue.push({ value: value[k], depth: depth + 1 });
    }
  }
  return undefined;
}

// ---------- AI Text Extraction ----------
function getAiTextAnyShape(data) {
  // Common n8n OpenAI "Responses" wrapper: [[{ content:[{text:"..."}] }]]
  if (Array.isArray(data) && Array.isArray(data[0]) && data[0][0]?.content?.[0]?.text) {
    return data[0][0].content[0].text;
  }

  // Merge output shape: { "0": { content:[{text:"..."}] }, ... }
  if (data?.["0"]?.content?.[0]?.text) {
    return data["0"].content[0].text;
  }

  // Direct: { content:[{text:"..."}] }
  if (data?.content?.[0]?.text) {
    return data.content[0].text;
  }

  // Last resort: search for a "text" field that looks like JSON
  const maybeText = deepFindKey(data, 'text');
  if (typeof maybeText === 'string' && maybeText.trim().startsWith('{')) {
    return maybeText;
  }

  return null;
}

// ---------- Normalize / extract JSON block ----------
function normalizeAndExtractJsonBlock(rawText) {
  let t = String(rawText || '').trim();

  // remove fences
  t = t.replace(/```json/gi, '```').replace(/```/g, '').trim();

  // normalize curly quotes
  t = t
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/\u00A0/g, ' ');

  const start = t.indexOf('{');
  if (start === -1) return '';
  t = t.slice(start);

  // If there's a full closing brace, keep only up to it (best case)
  const lastBrace = t.lastIndexOf('}');
  if (lastBrace !== -1) {
    return t.slice(0, lastBrace + 1).trim();
  }

  // Otherwise return truncated block
  return t.trim();
}

// ---------- Progressive trim parser (salvages valid prefix) ----------
function parseJsonSalvage(rawText) {
  const block = normalizeAndExtractJsonBlock(rawText);
  if (!block) return {};

  // 1) try direct
  try {
    return JSON.parse(block);
  } catch {}

  // 2) progressive trimming: cut from end to last comma boundary, close }
  let candidate = block;

  // If odd number of quotes, close string
  const quoteCount = (candidate.match(/"/g) || []).length;
  if (quoteCount % 2 === 1) candidate += '"';

  // Try up to 80 trims
  for (let i = 0; i < 80; i++) {
    candidate = candidate.trim();

    // Remove trailing comma
    candidate = candidate.replace(/,\s*$/g, '');

    // Close object
    if (!candidate.endsWith('}')) candidate = candidate + '\n}';

    try {
      return JSON.parse(candidate);
    } catch {
      // Remove the final "}" we added so we can cut properly
      candidate = candidate.replace(/\n\}\s*$/g, '').replace(/\}\s*$/g, '');

      const lastComma = candidate.lastIndexOf(',');
      if (lastComma === -1) break;

      candidate = candidate.slice(0, lastComma);
    }
  }

  return {};
}

// ---------- Regex fallback extraction for enquiry (works even if JSON parse fails) ----------
function extractEnquiryFromRaw(rawText) {
  const t = String(rawText || '');
  const m = t.match(/"enquiry"\s*:\s*"([\s\S]*?)(?:"\s*,\s*"|\s*"\s*[\}\n\r]|$)/i);
  if (!m || !m[1]) return '';
  return m[1]
    .replace(/\\"/g, '"')
    .replace(/\\n/g, '\n')
    .trim();
}

// ---------- Address fix ----------
function normalizeAddressToSuburbOnly(address) {
  const a = String(address || '').trim();
  if (!a) return a;

  const m = a.match(/^(.+?),\s*\d{4}\s*$/);
  if (m) return m[1].trim();

  const m2 = a.match(/^(.+?)\s+\d{4}\s*$/);
  if (m2) return m2[1].trim();

  return a;
}

// ---------- Discord content extractor (string only; avoids [object Object]) ----------
function getDiscordMessageText(data) {
  if (typeof data?.content === 'string') return data.content.trim();

  const found = deepFindKey(data, 'content');
  if (typeof found === 'string') return found.trim();

  return '';
}

// ---------- Extract DISCORD / IMAGES from AI enquiry format ----------
function splitAiEnquiry(aiEnquiry) {
  const s = String(aiEnquiry || '').trim();
  if (!s) return { discord: '', images: '' };

  const m = s.match(/^DISCORD:\s*([\s\S]*?)\s*\|\s*IMAGES:\s*([\s\S]*)$/i);
  if (m) {
    return { discord: (m[1] || '').trim(), images: (m[2] || '').trim() };
  }

  const mi = s.match(/IMAGES:\s*([\s\S]*)$/i);
  if (mi) {
    return { discord: '', images: (mi[1] || '').trim() };
  }

  return { discord: '', images: s };
}

// ---------- CRM Clean Enquiry Format ----------
function formatEnquiryCRM(discordText, imagesText) {
  const discord = String(discordText || '').trim();
  const images = String(imagesText || '').trim();

  const sections = [];
  if (discord) sections.push('===== DISCORD MESSAGE =====\n' + discord);
  if (images) sections.push('===== IMAGE DETAILS =====\n' + images);

  return sections.join('\n\n').trim();
}

// ---------- MAIN ----------
for (const item of inputItems) {
  const data = item.json;

  const rawText = getAiTextAnyShape(data);
  if (!rawText) {
    throw new Error('AI output not found. Make sure the Code node receives the AI node output.');
  }

  // Parse salvaging fields even when truncated
  const lead = parseJsonSalvage(rawText);

  // If enquiry missing due to truncation, try regex extraction
  if (!lead.enquiry) {
    lead.enquiry = extractEnquiryFromRaw(rawText);
  }

  // Fix address to suburb only
  if (lead.address !== undefined) {
    lead.address = normalizeAddressToSuburbOnly(lead.address);
  }

  // Build CRM enquiry:
  const discordFromMerge = getDiscordMessageText(data);
  const split = splitAiEnquiry(lead.enquiry);

  const finalDiscord = discordFromMerge || split.discord;
  const finalImages = split.images;

  // Enquiry formatted + Google Sheets safe
  lead.enquiry = safeForGoogleSheets(formatEnquiryCRM(finalDiscord, finalImages));

  const fileName = buildFileName(lead.firstName, lead.lastName);
  const Timestamp = nowBrisbaneTimestamp();

  // Remove unwanted fields + attachments here
  delete lead.guildId;
  delete lead.content;
  delete lead.aiStatus;
  delete lead.imageAttachments;

  // REMOVE THESE META FIELDS COMPLETELY
  delete lead.messageId;
  delete lead.channelId;
  delete lead.authorId;
  delete lead.authorName;

  const out = {
    ...lead,
    fileName,
    Timestamp,
  };

  outputItems.push({ json: out });
}

return outputItems;

// n8n Code node (merge lead + meta/attachments)
// - Keeps ALL original lead fields (address, postalCode, etc.)
// - Appends Discord message to end of enquiry ONLY if present
// - Forces referredBy to ""
// - Forces leadQualifier to "Good"

const lead = items[0].json;
const meta = items[1]?.json || {};
const attachments = meta.imageAttachments || [];

// Safely extract Discord message
const discordMessage = (meta.content || meta.message || meta.discordMessage || '')
  .toString()
  .trim();

// Existing enquiry from AI
const currentEnquiry = (lead.enquiry || '').toString().trim();

let mergedEnquiry = currentEnquiry;

// Append Discord section only if message exists
if (discordMessage) {
  mergedEnquiry = [
    currentEnquiry,
    '===== DISCORD MESSAGE =====',
    discordMessage,
  ]
    .filter(Boolean)
    .join('\n\n');
}

return [
  {
    json: {
      // KEEP EVERYTHING from AI lead (including address + postalCode)
      ...lead,

      // Meta fields from Discord item
      messageId: meta.messageId ?? lead.messageId ?? null,
      channelId: meta.channelId ?? lead.channelId ?? null,
      authorId: meta.authorId ?? lead.authorId ?? null,
      authorName: meta.authorName ?? lead.authorName ?? null,
      leadType: meta.leadType ?? lead.leadType ?? null,
      howDidYouHearAboutUs: meta.howDidYouHearAboutUs ?? lead.howDidYouHearAboutUs ?? null,

      // Force required overrides
      referredBy: "",
      leadQualifier: "Good",

      // Updated enquiry
      enquiry: mergedEnquiry,

      // Attachments
      imageAttachments: attachments,
    }
  }
];

const base = $input.first().json;
const imgs = Array.isArray(base.imageAttachments) ? base.imageAttachments : [];

if (!imgs.length) return [];

const cleanUrl = (u) => (u ? String(u).trim().replace(/&+$/g, "") : null);

return imgs.map((img) => {
  const url = cleanUrl(img?.url);
  const proxyURL = cleanUrl(img?.proxyURL);

  return {
    json: {
      image: img,
      imageFetchUrl: proxyURL || url || null,
    },
  };
});

// MAIN WORKFLOW Code node (place right AFTER Set/Map node)
// - Normalizes keys
// - Keeps formatting as literal "\n" (NOT real newlines)
// - Removes leading quote
// - Makes enquiry safe for HTTP "Using JSON"

const items = $input.all();

function firstNonUndefined(obj, keys) {
  for (const k of keys) {
    if (obj && Object.prototype.hasOwnProperty.call(obj, k)) return obj[k];
  }
  return undefined;
}

function clean(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

// Convert real newlines to literal "\n" and escape JSON-danger chars
function enquiryToLiteralNewlines(v) {
  if (v === null || v === undefined) return '';

  let s = String(v).trim();

  // remove leading single quote only
  s = s.replace(/^'+\s*/, '');

  // normalize CRLF -> LF
  s = s.replace(/\r\n/g, '\n');

  // escape backslashes + quotes to stay safe in JSON strings
  s = s.replace(/\\/g, '\\\\').replace(/"/g, '\\"');

  // convert real newlines to literal \n
  s = s.replace(/\n/g, '\\n');

  return s.trim();
}

return items.map((item) => {
  const j = item.json || {};

  const id = firstNonUndefined(j, ['id', 'Id']);
  const leadType = firstNonUndefined(j, ['leadType', 'Lead Type']);
  const firstName = firstNonUndefined(j, ['firstName', 'First Name']);
  const lastName = firstNonUndefined(j, ['lastName', 'Last Name']);

  const emailAddress = firstNonUndefined(j, ['emailAddress', 'Email Address']);
  const mobileNumber = firstNonUndefined(j, ['mobileNumber', 'Mobile Number']);
  const phoneNumber = firstNonUndefined(j, ['phoneNumber', 'Phone Number']);

  const address = firstNonUndefined(j, ['address', 'Address']);
  const suburb = firstNonUndefined(j, ['suburb', 'Suburb']);
  const state = firstNonUndefined(j, ['state', 'State']);
  const postalCode = firstNonUndefined(j, ['postalCode', 'Postal Code']);

  const enquiry = firstNonUndefined(j, ['enquiry', 'Enquiry']);
  const quantity = firstNonUndefined(j, ['quantity', 'Quantity']);
  const referredBy = firstNonUndefined(j, ['referredBy', 'Referred By', 'Referred by', 'ReferredBy']);
  const leadQualifier = firstNonUndefined(j, ['leadQualifier', 'Lead Qualifier']);
  const howTheyHeard = firstNonUndefined(j, ['howTheyHeardAboutUs', 'How they heard about us', 'How they heard about us?']);
  const underway = firstNonUndefined(j, [
    "IdLikeToGetMyProjectUnderway",
    "I’d Like To Get My Project Underway",
    "I'd Like To Get My Project Underway",
    "I'd Like to Get My Project Underway",
  ]);

  const out = {
    ...j,

    id: clean(id),
    leadType: clean(leadType),
    firstName: clean(firstName),
    lastName: clean(lastName),
    emailAddress: clean(emailAddress),
    mobileNumber: clean(mobileNumber),
    phoneNumber: clean(phoneNumber),
    address: clean(address),
    suburb: clean(suburb),
    state: clean(state),
    postalCode: clean(postalCode),

    // ✅ safe: contains literal "\n" instead of real newlines
    enquiry: enquiryToLiteralNewlines(enquiry),

    quantity: clean(quantity),
    referredBy: clean(referredBy),
    leadQualifier: clean(leadQualifier),
    howTheyHeardAboutUs: clean(howTheyHeard),
    IdLikeToGetMyProjectUnderway: clean(underway),
  };

  return { json: out };
});

