// ---------- AI Text Extraction ----------
function getAiTextAnyShape(data) {
  // Common n8n OpenAI "Responses" wrapper: [[{ content:[{text:"..."}] }]]
  if (Array.isArray(data) && Array.isArray(data[0]) && data[0][0]?.content?.[0]?.text) {
    return data[0][0].content[0].text;
  }

  // Merge output shape: { "0": { content:[{text:"..."}] }, ... }
  if (data?.["0"]?.content?.[0]?.text) {
    return data["0"].content[0].text;
  }

  // Direct: { content:[{text:"..."}] }
  if (data?.content?.[0]?.text) {
    return data.content[0].text;
  }

  // Last resort: search for a "text" field that looks like JSON
  const maybeText = deepFindKey(data, 'text');
  if (typeof maybeText === 'string' && maybeText.trim().startsWith('{')) {
    return maybeText;
  }

  return null;
}

// ---------- Normalize / extract JSON block ----------
function normalizeAndExtractJsonBlock(rawText) {
  let t = String(rawText || '').trim();

  // remove fences
  t = t.replace(/```json/gi, '```').replace(/```/g, '').trim();

  // normalize curly quotes
  t = t
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/\u00A0/g, ' ');

  const start = t.indexOf('{');
  if (start === -1) return '';
  t = t.slice(start);

  // If there's a full closing brace, keep only up to it (best case)
  const lastBrace = t.lastIndexOf('}');
  if (lastBrace !== -1) {
    return t.slice(0, lastBrace + 1).trim();
  }

  // Otherwise return truncated block
  return t.trim();
}

// ---------- Progressive trim parser (salvages valid prefix) ----------
function parseJsonSalvage(rawText) {
  const block = normalizeAndExtractJsonBlock(rawText);
  if (!block) return {};

  // 1) try direct
  try {
    return JSON.parse(block);
  } catch {}

  // 2) progressive trimming: cut from end to last comma boundary, close }
  let candidate = block;

  // If odd number of quotes, close string
  const quoteCount = (candidate.match(/"/g) || []).length;
  if (quoteCount % 2 === 1) candidate += '"';

  // Try up to 80 trims
  for (let i = 0; i < 80; i++) {
    candidate = candidate.trim();

    // Remove trailing comma
    candidate = candidate.replace(/,\s*$/g, '');

    // Close object
    if (!candidate.endsWith('}')) candidate = candidate + '\n}';

    try {
      return JSON.parse(candidate);
    } catch {
      // Remove the final "}" we added so we can cut properly
      candidate = candidate.replace(/\n\}\s*$/g, '').replace(/\}\s*$/g, '');

      const lastComma = candidate.lastIndexOf(',');
      if (lastComma === -1) break;

      candidate = candidate.slice(0, lastComma);
    }
  }

  return {};
}

// ---------- Regex fallback extraction for enquiry (works even if JSON parse fails) ----------
function extractEnquiryFromRaw(rawText) {
  const t = String(rawText || '');
  const m = t.match(/"enquiry"\s*:\s*"([\s\S]*?)(?:"\s*,\s*"|\s*"\s*[\}\n\r]|$)/i);
  if (!m || !m[1]) return '';
  return m[1]
    .replace(/\\"/g, '"')
    .replace(/\\n/g, '\n')
    .trim();
}

// ---------- Address fix ----------
function normalizeAddressToSuburbOnly(address) {
  const a = String(address || '').trim();
  if (!a) return a;

  const m = a.match(/^(.+?),\s*\d{4}\s*$/);
  if (m) return m[1].trim();

  const m2 = a.match(/^(.+?)\s+\d{4}\s*$/);
  if (m2) return m2[1].trim();

  return a;
}

// ---------- Discord content extractor (string only; avoids [object Object]) ----------
function getDiscordMessageText(data) {
  if (typeof data?.content === 'string') return data.content.trim();

  const found = deepFindKey(data, 'content');
  if (typeof found === 'string') return found.trim();

  return '';
}

// ---------- Extract DISCORD / IMAGES from AI enquiry format ----------
function splitAiEnquiry(aiEnquiry) {
  const s = String(aiEnquiry || '').trim();
  if (!s) return { discord: '', images: '' };

  const m = s.match(/^DISCORD:\s*([\s\S]*?)\s*\|\s*IMAGES:\s*([\s\S]*)$/i);
  if (m) {
    return { discord: (m[1] || '').trim(), images: (m[2] || '').trim() };
  }

  const mi = s.match(/IMAGES:\s*([\s\S]*)$/i);
  if (mi) {
    return { discord: '', images: (mi[1] || '').trim() };
  }

  return { discord: '', images: s };
}

// ---------- CRM Clean Enquiry Format ----------
function formatEnquiryCRM(discordText, imagesText) {
  const discord = String(discordText || '').trim();
  const images = String(imagesText || '').trim();

  const sections = [];
  if (discord) sections.push('===== DISCORD MESSAGE =====\n' + discord);
  if (images) sections.push('===== IMAGE DETAILS =====\n' + images);

  return sections.join('\n\n').trim();
}

// ---------- MAIN ----------
for (const item of inputItems) {
  const data = item.json;

  const rawText = getAiTextAnyShape(data);
  if (!rawText) {
    throw new Error('AI output not found. Make sure the Code node receives the AI node output.');
  }

  // Parse salvaging fields even when truncated
  const lead = parseJsonSalvage(rawText);

  // If enquiry missing due to truncation, try regex extraction
  if (!lead.enquiry) {
    lead.enquiry = extractEnquiryFromRaw(rawText);
  }

  // Fix address to suburb only
  if (lead.address !== undefined) {
    lead.address = normalizeAddressToSuburbOnly(lead.address);
  }

  // Build CRM enquiry:
  const discordFromMerge = getDiscordMessageText(data);
  const split = splitAiEnquiry(lead.enquiry);

  const finalDiscord = discordFromMerge || split.discord;
  const finalImages = split.images;

  // Enquiry formatted + Google Sheets safe
  lead.enquiry = safeForGoogleSheets(formatEnquiryCRM(finalDiscord, finalImages));

  const fileName = buildFileName(lead.firstName, lead.lastName);
  const Timestamp = nowBrisbaneTimestamp();

  // Remove unwanted fields + attachments here
  delete lead.guildId;
  delete lead.content;
  delete lead.aiStatus;
  delete lead.imageAttachments;

  // REMOVE THESE META FIELDS COMPLETELY
  delete lead.messageId;
  delete lead.channelId;
  delete lead.authorId;
  delete lead.authorName;

  const out = {
    ...lead,
    fileName,
    Timestamp,
  };

  outputItems.push({ json: out });
}

return outputItems;

