// MAIN WORKFLOW Code node (place right AFTER Set/Map node)
// - Normalizes keys
// - Keeps formatting as literal "\n" (NOT real newlines)
// - Removes leading quote
// - Makes enquiry safe for HTTP "Using JSON"

const items = $input.all();

function firstNonUndefined(obj, keys) {
  for (const k of keys) {
    if (obj && Object.prototype.hasOwnProperty.call(obj, k)) return obj[k];
  }
  return undefined;
}

function clean(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

// Convert real newlines to literal "\n" and escape JSON-danger chars
function enquiryToLiteralNewlines(v) {
  if (v === null || v === undefined) return '';

  let s = String(v).trim();

  // remove leading single quote only
  s = s.replace(/^'+\s*/, '');

  // normalize CRLF -> LF
  s = s.replace(/\r\n/g, '\n');

  // escape backslashes + quotes to stay safe in JSON strings
  s = s.replace(/\\/g, '\\\\').replace(/"/g, '\\"');

  // convert real newlines to literal \n
  s = s.replace(/\n/g, '\\n');

  return s.trim();
}

return items.map((item) => {
  const j = item.json || {};

  const id = firstNonUndefined(j, ['id', 'Id']);
  const leadType = firstNonUndefined(j, ['leadType', 'Lead Type']);
