  const enquiry = firstNonUndefined(j, ['enquiry', 'Enquiry']);
  const quantity = firstNonUndefined(j, ['quantity', 'Quantity']);
  const referredBy = firstNonUndefined(j, ['referredBy', 'Referred By', 'Referred by', 'ReferredBy']);
  const leadQualifier = firstNonUndefined(j, ['leadQualifier', 'Lead Qualifier']);
  const howTheyHeard = firstNonUndefined(j, ['howTheyHeardAboutUs', 'How they heard about us', 'How they heard about us?']);
  const underway = firstNonUndefined(j, [
